-- =============================================================
-- SOURCE MySQL : Système RH & Ventes des représentants
-- =============================================================

CREATE DATABASE IF NOT EXISTS db_ventes_rh;
USE db_ventes_rh;

DROP TABLE IF EXISTS ventes;
DROP TABLE IF EXISTS vendeurs;

CREATE TABLE vendeurs (
    id_vendeur     INT AUTO_INCREMENT PRIMARY KEY,
    nom            VARCHAR(50),
    prenom         VARCHAR(50),
    salaire        DECIMAL(10,2),
    date_embauche  DATE,
    ville_base     VARCHAR(50),
    groupe         VARCHAR(30)
);


DROP TABLE IF EXISTS ventes;

CREATE TABLE ventes (
    id_vente          INT AUTO_INCREMENT PRIMARY KEY,
    id_vendeur        INT,
    id_client         INT,
    id_produit        INT,
    date_commande     DATE,
    date_precommande  DATE,
    quantite          INT,
    montant_vente     DECIMAL(10,2),
    montant_precom    DECIMAL(10,2),
    km_parcourus      INT,
    litres_essence    DECIMAL(8,2),
    frais_voyage      DECIMAL(8,2),
    nb_visites        INT,
    ville_visite      VARCHAR(50),
    FOREIGN KEY (id_vendeur) REFERENCES vendeurs(id_vendeur)
);

